	__global int* d_Row,
	__global int* d_Col,
	__global int* d_tRowLoc,
	__global int* d_tColLoc,
	__global fp* d_T,
	__global fp* d_in2,
	__global fp* d_conv,
	__global fp* d_in2_pad_cumv,
	__global fp* d_in2_pad_cumv_sel,
	__global fp* d_in2_sub_cumh,
	__global fp* d_in2_sub_cumh_sel,
	__global fp* d_in2_sub2,
	__global fp* d_in2_sqr,
	__global fp* d_in2_sqr_sub2,
	__global fp* d_in_sqr,
