	kernel_impl(d_Row,d_Col,d_tRowLoc,d_tColLoc,d_T,d_in2,d_conv,d_in2_pad_cumv,d_in2_pad_cumv_sel,
				d_in2_sub_cumh,d_in2_sub_cumh_sel,d_in2_sub2,d_in2_sqr,d_in2_sqr_sub2,d_in_sqr,
				d_tMask,d_mask_conv,d_frame,frame_no,points,d_common);
}

